import{_ as e,j as a,o as t,v as n}from"./chunks/framework.OlxNbC8G.js";const s=JSON.parse('{"title":"Message queue là gì ?","description":"","frontmatter":{"footer":true,"title":"Message queue là gì ?","authors":["lethanh"],"date":"2024-04-15T00:00:00.000Z","outline":"deep","draft":true,"group":"2. Message and event stream"},"headers":[{"level":2,"title":"Vậy Message queue là gì ?","slug":"vay-message-queue-la-gi","link":"#vay-message-queue-la-gi","children":[]},{"level":2,"title":"Đặc điểm của event.","slug":"đac-điem-cua-event","link":"#đac-điem-cua-event","children":[]}],"relativePath":"study/thanhlv-study-2024/2024-04-15-message-queue-la-gi.md","filePath":"study/thanhlv-study-2024/2024-04-15-message-queue-la-gi.md","lastUpdated":1715527409000}'),g={name:"study/thanhlv-study-2024/2024-04-15-message-queue-la-gi.md"},u=[n('<h1 id="message-queue-la-gi" tabindex="-1">Message queue là gì ? <a class="header-anchor" href="#message-queue-la-gi" aria-label="Permalink to &quot;Message queue là gì ?&quot;">​</a></h1><p>Kiến thức đầu tiên chúng ta đã cùng học với nhau là <a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a>, trong bài viết này chúng ta sẽ cùng nhau tìm hiểu về <a href="./2024-04-15-message-queue-la-gi.html"><strong>Message queue</strong></a>, một khái niệm quan trọng mà các hệ thống lớn thường sử dụng để gửi và nhận các tin nhắn giữa các thành phần của chúng.</p><nav class="table-of-contents"><ul><li><a href="#vay-message-queue-la-gi">Vậy Message queue là gì ?</a></li><li><a href="#đac-điem-cua-event">Đặc điểm của event.</a></li></ul></nav><h2 id="vay-message-queue-la-gi" tabindex="-1">Vậy Message queue là gì ? <a class="header-anchor" href="#vay-message-queue-la-gi" aria-label="Permalink to &quot;Vậy Message queue là gì ?&quot;">​</a></h2><p><a href="./2024-04-15-message-queue-la-gi.html"><strong>Message queue (Hàng đợi tin nhấn)</strong></a> là một cơ chế lưu trữ các tin nhắn (<a href="./2024-04-15-message-la-gi.html"><strong>Message</strong></a>) trong một hàng đợi(Queue) theo thứ tự tuần tự hoặc ưu tiên.</p><p><a href="./2024-04-15-message-queue-la-gi.html"><strong>Message queue (Hàng đợi tin nhấn)</strong></a> cho phép các ứng dụng giao tiếp và trao đổi dữ liệu bất đồng bộ.</p><p>Trong một hệ thống có <a href="./2024-04-15-message-queue-la-gi.html"><strong>Message queue (Hàng đợi tin nhấn)</strong></a>, các tin nhắn được gửi từ một ứng dụng A đến ứng dụng B sẽ được tạm thời lưu trữ trong hàng đợi(Queue) trước khi được ứng dụng B lấy ra và xử lý. Điều này sẽ cho phép các ứng dụng làm việc độc lập với nhau, không cần kết nối trực tiếp.</p><h2 id="đac-điem-cua-event" tabindex="-1">Đặc điểm của event. <a class="header-anchor" href="#đac-điem-cua-event" aria-label="Permalink to &quot;Đặc điểm của event.&quot;">​</a></h2>',8)];const i=e(g,[["render",function(e,n,s,g,i,l){return t(),a("div",null,u)}]]);export{s as __pageData,i as default};
